class CountUpLite{constructor(el,end,duration=1300){this.el=el;this.end=Number(end)||0;this.duration=duration}start(){const start=performance.now();const tick=now=>{const p=Math.min((now-start)/this.duration,1);const eased=1-Math.pow(1-p,3);this.el.textContent=Math.floor(this.end*eased).toLocaleString();if(p<1)requestAnimationFrame(tick)};requestAnimationFrame(tick)}}
